exercises.solution_code:
#include <iostream>
#include <iomanip>

class Temperature {
public:
    Temperature(double celsius)
        : celsius_{celsius} {}

    double getCelsius() const {
        return celsius_;
    }

    double getFahrenheit() const {
        return celsius_ * 9.0 / 5.0 + 32.0;
    }

private:
    double celsius_;
};

int main() {
    double c;
    std::cin >> c;

    Temperature t{c};

    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Celsius: " << t.getCelsius() << '\n';
    std::cout << "Fahrenheit: " << t.getFahrenheit() << '\n';

    return 0;
}

