#include <iostream>

class Rectangle {
private:
    int width{};
    int height{};

public:
    Rectangle(int w, int h) : width{w}, height{h} {}

    int area() const {
        return width * height;
    }

    int perimeter() const {
        return 2 * (width + height);
    }

    void display() const {
        std::cout << "Rectangle " << width << " x " << height
                  << ": area = " << area()
                  << ", perimeter = " << perimeter() << '\n';
    }
};

