#include <iostream>
#include <string>

class BoundedCounter
{
    std::string m_name;
    int m_max;
    int m_value{0};
    int m_resets{0};
public:
    BoundedCounter(std::string name, int max)
        : m_name{std::move(name)}, m_max{max}
    {}

    void increment()
    {
        if (m_value < m_max)
            ++m_value;
    }

    void reset()
    {
        m_value = 0;
        ++m_resets;
    }

    int         value()  const { return m_value;  }
    int         resets() const { return m_resets; }
    std::string name()   const { return m_name;   }
};

int main()
{
    int n{};
    std::cin >> n;

    for (int i{0}; i < n; ++i)
    {
        std::string cname{};
        int maxVal{};
        std::cin >> cname >> maxVal;

        BoundedCounter bc{cname, maxVal};

        int inc1{};
        std::cin >> inc1;
        for (int j{0}; j < inc1; ++j)
            bc.increment();

        int resetCount{};
        std::cin >> resetCount;
        for (int j{0}; j < resetCount; ++j)
            bc.reset();

        int inc2{};
        std::cin >> inc2;
        for (int j{0}; j < inc2; ++j)
            bc.increment();

        std::cout << bc.name() << ": value=" << bc.value()
                  << " resets=" << bc.resets() << '\n';
    }

    return 0;
}

