#include <iostream>
#include <iomanip>
#include <string>

struct Student {
private:
    std::string name;
    int grades[5]{};
    int count{};

public:
    Student(const std::string& n, const int* g, int cnt)
        : name{n}, count{cnt} {
        for (int i = 0; i < count; ++i)
            grades[i] = g[i];
    }

    Student(const Student& src) : count{src.count} {
        std::cout << "Copy constructor called for: " << src.name << "\n";
        name = src.name;
        for (int i = 0; i < count; ++i)
            grades[i] = src.grades[i];
    }

    double average() const {
        double sum = 0;
        for (int i = 0; i < count; ++i)
            sum += grades[i];
        return sum / count;
    }

    const std::string& getName() const { return name; }

    int getGrade(int i) const { return grades[i]; }

    void rename(const std::string& newName) { name = newName; }

    int getCount() const { return count; }
};

int main() {
    std::string name;
    int n;
    std::cin >> name >> n;

    int g[5]{};
    for (int i = 0; i < n; ++i)
        std::cin >> g[i];

    Student original{name, g, n};
    Student copy = original;
    copy.rename("Clone");

    std::cout << "Original: " << original.getName() << " avg=" << std::fixed << std::setprecision(2) << original.average() << "\n";
    // Note: copy constructor line already printed above
    std::cout << "Copy: " << copy.getName() << " avg=" << std::fixed << std::setprecision(2) << copy.average() << "\n";
    std::cout << "After rename, original: " << original.getName() << " avg=" << std::fixed << std::setprecision(2) << original.average() << "\n";
    std::cout << "After rename, copy: " << copy.getName() << " avg=" << std::fixed << std::setprecision(2) << copy.average() << "\n";

    bool match = true;
    for (int i = 0; i < original.getCount(); ++i)
        if (original.getGrade(i) != copy.getGrade(i)) { match = false; break; }
    std::cout << "Grades match: " << (match ? "yes" : "no") << "\n";

    return 0;
}

