#include <iostream>
#include <iomanip>

class Temperature
{
    double m_celsius{};
public:
    constexpr explicit Temperature(double celsius) : m_celsius{celsius} {}

    constexpr double celsius()     const { return m_celsius; }
    constexpr double fahrenheit()  const { return m_celsius * 9.0 / 5.0 + 32.0; }
    constexpr double kelvin()      const { return m_celsius + 273.15; }

    static constexpr Temperature fromCelsius(double c)
    {
        return Temperature{c};
    }

    static constexpr Temperature fromFahrenheit(double f)
    {
        return Temperature{(f - 32.0) * 5.0 / 9.0};
    }

    static constexpr Temperature fromKelvin(double k)
    {
        return Temperature{k - 273.15};
    }
};

int main()
{
    static_assert(Temperature::fromCelsius(0.0).fahrenheit() == 32.0);
    static_assert(Temperature::fromFahrenheit(212.0).celsius() == 100.0);

    double value{};
    char scale{};
    std::cin >> value >> scale;

    Temperature temp =
        (scale == 'F') ? Temperature::fromFahrenheit(value) :
        (scale == 'K') ? Temperature::fromKelvin(value) :
                         Temperature::fromCelsius(value);

    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Celsius: "    << temp.celsius()    << '\n';
    std::cout << "Fahrenheit: " << temp.fahrenheit() << '\n';
    std::cout << "Kelvin: "     << temp.kelvin()     << '\n';

    return 0;
}

